  `PartidoId` int(11) NOT NULL,
  `EquipoId` int(11) NOT NULL,
  `JugadorId` int(11) DEFAULT NULL,
  `Minuto` int(11) NOT NULL,
  `Tipo` varchar(50) DEFAULT NULL,
  `Detalle` varchar(50) DEFAULT NULL,
