  PRIMARY KEY (`EventoPartidoId`),
  KEY `IX_EventosPartidos_EquipoId` (`EquipoId`),
  KEY `IX_EventosPartidos_JugadorId` (`JugadorId`),
  KEY `IX_EventosPartidos_PartidoId` (`PartidoId`),
  KEY `IX_EventosPartidos_PartidoId_Minuto` (`PartidoId`,`Minuto`),
  CONSTRAINT `FK_EventosPartidos_Equipos_EquipoId` FOREIGN KEY (`EquipoId`) REFERENCES `equipos` (`EquipoId`),
  CONSTRAINT `FK_EventosPartidos_Jugadores_JugadorId` FOREIGN KEY (`JugadorId`) REFERENCES `jugadores` (`JugadorId`) ON DELETE SET NULL,
  CONSTRAINT `FK_EventosPartidos_Partidos_PartidoId` FOREIGN KEY (`PartidoId`) REFERENCES `partidos` (`PartidoId`) ON DELETE CASCADE
